mapper.select:
SELECT  
  FROM  TB_ANNVRSRY_MANAGE A
 WHERE  A.ANNVRSRY_ID = #{annId}

SELECT  COUNT(*)
  FROM  TB_ANNVRSRY_MANAGE
 WHERE  ANNVRSRY_NM = #{annvrsryNm}
   AND  ANNVRSRY = #{annvrsryDe}

mapper.insert:
INSERT  INTO TB_ANNVRSRY_MANAGE
      ( ANNVRSRY_ID
      , USER_ID
      , ANNVRSRY_SE
      , ANNVRSRY_NM
      , ANNVRSRY
      , CLDR_SE
      , ANNVRSRY_NTCN_SETUP
      , ANNVRSRY_NTCN_BGNDE
      , MEMO
      , REPTIT_AT
      , FRST_REGISTER_ID
      , FRST_REGIST_PNTTM )
VALUES  ( #{annId}
        , #{usid}
        , #{annvrsrySe}
        , #{annvrsryNm}
        , #{annvrsryDe}
        , #{cldrSe}
        , #{annvrsrySetup}
        , #{annvrsryBeginDe}
        , #{memo}
        , #{reptitSe}
        , #{frstRegisterId}
        , CURRENT_TIMESTAMP )

mapper.update:
UPDATE  TB_ANNVRSRY_MANAGE
   SET  ANNVRSRY_SE     = #{annvrsrySe}
      , ANNVRSRY_NM     = #{annvrsryNm}
      , ANNVRSRY        = #{annvrsryDe}
      , CLDR_SE         = #{cldrSe}
      , MEMO            = #{memo}
      , REPTIT_AT       = #{reptitSe}
      , LAST_UPDUSR_ID  = #{lastUpdusrId}
      , LAST_UPDT_PNTTM = CURRENT_TIMESTAMP
 WHERE  ANNVRSRY_ID = #{annId}
